```
const handleKeyUp = (e: React.KeyboardEvent<HTMLInputElement>) => {
  if (e.key === 'Enter') {
    console.log(e);
    e.preventDefault();
  }
};
```
This should work and prevent the form submission when the Enter key is pressed in the `<input>` element.

