2. If that does not work, another approach would be to add a new state to your component and toggle it based on whether the Enter key is pressed in the input field. Then you can conditionally render the `<TagsInput>` component based on this state, like this:

```
const [submitOnEnter, setSubmitOnEnter] = useState(true);

const handleKeyUp = (e: React.KeyboardEvent<HTMLInputElement>) => {
  if (e.key === 'Enter') {
    setSubmitOnEnter(false);
    e.preventDefault();
  }
};

return (
  <FormField {...formFieldProps}>
    {submitOnEnter ? (
      <Container
        isError={!!error}
        onClick={handleClick}
        onKeyDown={handleKeyUp}
      >
        <input type="text" placeholder={placeholder} onKeyUp={handleKeyUp} />
      </Container>
    ) : (
      <Container isError={!!error} onClick={handleClick}>
        <TagsInput
          value={formatValue(value)}
          onChange={onChange}
          name={name}
          onBlur={handleBlur}
          placeHolder={placeholder}
          onKeyUp={handleKeyUp}
        />
      </Container>
    )}
  </FormField>
);
```

In this approach, when the Enter key is pressed, `handleKeyUp` function will set the `submitOnEnter` state to `false` and the `<TagsInput>` component will be hidden and replaced with a simple `<input>` element. This will prevent form submission on subsequent Enter key presses.

