In that case, we can try using a CSS hack to prevent form submission when the Enter key is pressed within the `<TagsInput>` component. Here is the modified code:

```
const containerRef = React.useRef<HTMLDivElement>(null);

React.useEffect(() => {
  const containerElement = containerRef.current;
  const inputElement = containerElement?.querySelector("input");

  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Enter" && e.target === inputElement) {
      e.preventDefault();
    }
  };

  containerElement?.addEventListener("keydown", handleKeyDown);

  return () => {
    containerElement?.removeEventListener("keydown", handleKeyDown);
  };
}, []);

